1025	            failure_type: e.failure_type.clone(),
1026	            description: e.description.clone(),
1027	            recovery_actions: e.recovery_actions.clone(),
1028	            should_retry: e.should_retry,
1029	            max_retries: e.max_retries as u32,
1030	        },
1031	        None => return None,
1032	    };
1033	
1034	    Some(ans_core::signal::EyeReport {
1035	        eye_name,
1036	        timestamp: chrono::Utc::now(),
